// --- ส่วนหัวแก้ Bug ตอน Test ---
let staticData;
try {
    staticData = getWorkflowStaticData('global');
} catch (error) {
    staticData = { lastFolder: 'TEST_MODE', lastSong: '' }; 
}

// ⭐ [โหมดทดสอบ]
const FORCE_TEST_JINGLE = false; 

if (FORCE_TEST_JINGLE) {
    staticData.lastFolder = "FAKE_OLD_MOOD"; 
}
// ---------------------------------

const now = new Date();
const hour = now.getHours();

// ดึงข้อมูลสภาพอากาศ (กัน Error ถ้าไม่มีข้อมูล)
const weatherData = $node["🌤️ SENSOR: WEATHER_DATA"] ? $node["🌤️ SENSOR: WEATHER_DATA"].json : { weather: [{ main: "Clear" }] };
const weatherMain = weatherData.weather[0].main; 

// เช็คว่าฝนตกไหม?
const isRaining = (weatherMain === "Rain" || weatherMain === "Drizzle" || weatherMain === "Thunderstorm");

// ====================================================
// 🎵 คลังเพลงส่วนกลาง (All Day Lofi)
// ⚠️ ใส่ชื่อไฟล์เพลงของคุณที่นี่ (อย่าลืมใส่นามสกุลไฟล์ เช่น .mp3 หรือ .wav)
// ====================================================
const allDayPlaylist = [
    "your_allday_song_1.mp3", 
    "your_allday_song_2.mp3",
    "your_allday_song_3.mp3"
];

// ตัวแปรสำหรับเพลงที่จะเปิดตามเวลา
let mainFolder = "";  
let subFolder = "";   
let targetMood = "";
let playlist = [];

// ====================================================
// 🕒 TIMELINE LOGIC (ตั้งค่าโฟลเดอร์เพลงประจำช่วงเวลา)
// ⚠️ แก้ไขชื่อเพลงใน playlist ให้ตรงกับไฟล์ที่คุณมี
// ====================================================

// 1. กลางคืน (00:00 - 04:00)
if (hour >= 0 && hour < 4) {
    mainFolder = "01_Night_00-04"; // ⚠️ เปลี่ยนชื่อโฟลเดอร์ย่อยถ้าจำเป็น
    if (isRaining) {
        subFolder = "Rain";
        targetMood = "Midnight Rain (Melancholy)";
        playlist = ["night_rain_1.mp3", "night_rain_2.mp3"];
    } else {
        subFolder = "Normal";
        targetMood = "Lofi Midnight Vibes";
        playlist = ["night_normal_1.mp3", "night_normal_2.mp3"];
    }
}
// 2. ก่อนเช้า (04:00 - 07:00)
else if (hour >= 4 && hour < 7) {
    mainFolder = "02_PreDawn_04-07";
    if (isRaining) {
        subFolder = "Rain";
        targetMood = "Soft Rainlight";
        playlist = ["dawn_rain_1.mp3"];
    } else {
        subFolder = "Normal";
        targetMood = "Pre-Dawn Echo";
        playlist = ["dawn_normal_1.mp3"];
    }
}
// 3. เช้า (07:00 - 10:00)
else if (hour >= 7 && hour < 10) {
    mainFolder = "03_Morning_07-10";
    if (isRaining) {
        subFolder = "Rain";
        targetMood = "Rainy Solitude";
        playlist = ["morning_rain_1.mp3"];
    } else {
        subFolder = "Normal";
        targetMood = "Clarity Morning";
        playlist = ["morning_normal_1.mp3"];
    }
}
// 4. กลางวัน (10:00 - 14:00)
else if (hour >= 10 && hour < 14) {
    mainFolder = "04_Day_10-14";
    if (isRaining) {
        subFolder = "Rain";
        targetMood = "Wet Daydream";
        playlist = ["day_rain_1.mp3"];
    } else {
        subFolder = "Normal";
        targetMood = "Stillness Field";
        playlist = ["day_normal_1.mp3"];
    }
}
// 5. เย็น (14:00 - 18:00)
else if (hour >= 14 && hour < 18) {
    mainFolder = "05_Evening_14-18";
    if (isRaining) {
        subFolder = "Rain";
        targetMood = "Rain on Warm Glass";
        playlist = ["evening_rain_1.mp3"];
    } else {
        subFolder = "Normal";
        targetMood = "Golden Fade";
        playlist = ["evening_normal_1.mp3"];
    }
}
// 6. หัวค่ำ (18:00 - 22:00)
else if (hour >= 18 && hour < 22) {
    mainFolder = "06_Dusk_18-22";
    if (isRaining) {
        subFolder = "Rain";
        targetMood = "Glow & Drizzle";
        playlist = ["dusk_rain_1.mp3"];
    } else {
        subFolder = "Normal";
        targetMood = "Evening Console";
        playlist = ["dusk_normal_1.mp3"];
    }
}
// 7. ก่อนเที่ยงคืน (22:00 - 00:00)
else {
    mainFolder = "07_LateNight_22-00";
    if (isRaining) {
        subFolder = "Rain";
        targetMood = "Sleep Drift";
        playlist = ["latenight_rain_1.mp3"];
    } else {
        subFolder = "Normal";
        targetMood = "Last Thought";
        playlist = ["latenight_normal_1.mp3"];
    }
}

// ====================================================
// 🎲 ระบบสุ่ม: 90% All Day Lofi / 10% เพลงเฉพาะเวลา
// ====================================================

const rollAllDay = Math.random() < 0.90; 

let selectedPlaylist = [];
let selectedFolder = "";
let selectedMood = "";

if (rollAllDay) {
    selectedPlaylist = allDayPlaylist;
    selectedFolder = "All_Day_Lofi"; // ⚠️ ชื่อโฟลเดอร์คลังกลาง
    selectedMood = "All Day Chill"; 
} else {
    selectedPlaylist = playlist;
    selectedFolder = `${mainFolder}/${subFolder}`; 
    selectedMood = targetMood;
}

// --- 3. 🎵 ระบบ Jingle & ระบบกันสุ่มซ้ำ (Anti-Repeat) ---

let finalPath = "";
let finalSong = "";
let finalMood = "";
let isJingle = false;

function getRandomSong(list) {
    if (list.length === 0) return "";
    if (list.length === 1) return list[0]; 

    let availableSongs = list.filter(song => song !== staticData.lastSong);
    if (availableSongs.length === 0) availableSongs = list; 

    return availableSongs[Math.floor(Math.random() * availableSongs.length)];
}

let currentFolderKey = `${mainFolder}/${subFolder}`; 
const memoryFolder = staticData.lastFolder; 

if (memoryFolder === '00_Station_ID') {
    finalSong = getRandomSong(selectedPlaylist);
    finalPath = `${selectedFolder}/${finalSong}`;
    finalMood = selectedMood;
    staticData.lastFolder = currentFolderKey; 
    staticData.lastSong = finalSong;
}
else if (currentFolderKey !== memoryFolder && memoryFolder !== undefined && memoryFolder !== 'TEST_MODE') {
    // ⚠️ ใส่ชื่อไฟล์ Jingle คั่นรายการของคุณ
    finalPath = "00_Station_ID/Channel_Theme.mp3"; 
    finalSong = "Channel_Theme.mp3"; 
    finalMood = "Station ID (Switching)";
    isJingle = true;
    staticData.lastFolder = '00_Station_ID';
}
else {
    finalSong = getRandomSong(selectedPlaylist);
    finalPath = `${selectedFolder}/${finalSong}`;
    finalMood = selectedMood;
    staticData.lastFolder = currentFolderKey; 
    staticData.lastSong = finalSong;
}

// ====================================================
// ⚠️ เช็ค Path โฟลเดอร์เพลงหลักของคุณที่นี่ 
// (สำหรับ Windows ให้ใช้ \\ สองตัว เช่น "C:\\Users\\Name\\Music\\Library\\")
// ====================================================
const baseDir = "C:\\YOUR_MUSIC_FOLDER_PATH\\";

return {
    command_id: Math.floor(Date.now() / 1000),
    current_mood: finalMood,
    weather_status: weatherMain,
    filename: finalSong,
    full_path: `${baseDir}${finalPath}`,
    web_path: `music/YOUR_MUSIC_FOLDER/${finalPath}`, 
    is_jingle: isJingle,
    timestamp: Date.now()
};

// 1-Click Script: Convert Text to n8n Binary Data
for (const item of $input.all()) {
  const rawPath = item.json.full_path || "";
  const songName = rawPath.split('/').pop().replace('.mp3', '').replace('.wav', '');
  const jsContent = 'var currentSong = ' + JSON.stringify(songName) + ';';

  item.binary = {
    data: {
      data: Buffer.from(jsContent).toString('base64'),
      mimeType: 'application/javascript',
      fileName: 'song_data.js'
    }
  };
}
return $input.all();
